// Description: Collects per-application ArgoCD sync, health, and reconciliation metrics via Thanos Querier.
// Description: Maps sync_status and health_status labels to numeric values for alerting.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("openshift.thanos.host")
def token = hostProps.get("openshift.thanos.pass")
def port = hostProps.get("openshift.thanos.port") ?: "443"
def useSsl = (hostProps.get("openshift.thanos.ssl") ?: "true").toLowerCase() == "true"

def appName = instanceProps.get("auto.app.name")
def namespace = instanceProps.get("auto.app.namespace")

def results = [
    "sync_status": 0,
    "health_status": 0,
    "reconcile_count": 0,
    "p95_reconcile_ms": 0
]

if (!host || !token || !appName) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def executeQuery(String promql, String baseUrl, String token) {
    try {
        def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = conn.inputStream.text
            def json = new JsonSlurper().parseText(response)
            if (json.status == "success" && json.data?.result?.size() > 0) {
                def val = json.data.result[0].value[1]
                return val?.toString()?.isNumber() ? val : null
            }
        } else {
            System.err.println("Query failed: HTTP ${conn.responseCode} for: ${promql}")
        }
    } catch (Exception e) {
        System.err.println("Query error for ${promql}: ${e.message}")
    }
    return null
}

def an = appName.replace('"', '\\"')
def ns = namespace.replace('"', '\\"')

// Sync status: check if Synced label exists for this app
def syncVal = executeQuery('argocd_app_info{name="' + an + '",namespace="' + ns + '",sync_status="Synced"}', baseUrl, token)
results["sync_status"] = syncVal != null ? 1 : 0

// Health status: map label values to numeric codes
def healthMap = ["Healthy": 1, "Degraded": 2, "Missing": 3]
healthMap.each { status, code ->
    def hVal = executeQuery('argocd_app_info{name="' + an + '",namespace="' + ns + '",health_status="' + status + '"}', baseUrl, token)
    if (hVal != null) {
        results["health_status"] = code
    }
}

// Reconciliation rate
def reconVal = executeQuery('sum(rate(argocd_app_reconcile_count{name="' + an + '",namespace="' + ns + '"}[5m])) or vector(0)', baseUrl, token)
results["reconcile_count"] = reconVal ?: results["reconcile_count"]

// P95 reconciliation latency
def p95Val = executeQuery('histogram_quantile(0.95, sum(rate(argocd_app_reconcile_bucket{name="' + an + '",namespace="' + ns + '"}[5m])) by (le)) * 1000', baseUrl, token)
if (p95Val != null) {
    def p95Num = p95Val as Double
    results["p95_reconcile_ms"] = p95Num.isNaN() || p95Num.isInfinite() ? 0 : p95Val
}

results.each { k, v -> println("${k}:${v}") }
return 0
